int* findDisappearedNumbers(int* nums, int n, int* rs) {
    for(int i=0;i<n;i++){ int j=abs(nums[i])-1; nums[j]=-abs(nums[j]); }
    int* ans=malloc(n*sizeof(int)); *rs=0;
    for(int i=0;i<n;i++) if(nums[i]>0) ans[(*rs)++]=i+1;
    return ans;
}
